module verified_up_down_counter(
    input clk,
    input rst,
    input up,
    input down,
    output reg [2:0] count
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            count <= 3'b000;
        else if (up && !down)
            count <= count + 1;
        else if (!up && down)
            count <= count - 1;
    end
endmodule
